// --- Config ---
const FONT_SIZE = 13
const FONT = `${FONT_SIZE}px "Inter", sans-serif`
const LH = Math.round(FONT_SIZE * 1.55)
const UI_FONT_SIZE = 13
const MOUSE_R = 48
const MIN_SEGMENT = 25
const SCROLL_RATE = 1.5 // columns of text scrolled per second
const SMOOTHING = 0.35 // how fast the smoothed bands chase the real ones (0-1)

const canvas = document.getElementById('canvas') as HTMLCanvasElement
const ctx = canvas.getContext('2d')!

// --- Video panel elements ---
const btnToggle = document.getElementById('btn-toggle') as HTMLSpanElement
const videoPanel = document.getElementById('video-panel') as HTMLDivElement
const ytFrame = document.getElementById('yt-frame') as HTMLIFrameElement
const twitterLink = document.getElementById('twitter-link') as HTMLAnchorElement
const chromeCta = document.getElementById('chrome-cta') as HTMLDivElement
const openChromeCopy = document.getElementById('open-chrome-copy') as HTMLSpanElement

let mouseX = -9999
let mouseY = -9999
let W = 0
let H = 0
let prepared: PreparedTextWithSegments
let textCursors: LayoutCursor[] = [] // pre-computed cursor at each line boundary
let audioActive = false // true when waveform is actually moving
let activeTime = 0     // accumulated ms of active audio (energy-weighted)
let lastFrameTime = 0
let audioEnergy = 0    // 0..1 normalized audio level

// --- Audio state ---
let analyser: AnalyserNode | null = null
let freqData: Uint8Array | null = null
let smoothBands: Float32Array = new Float32Array(0)
let audioConnected = false

function isChromeBrowser() {
  const ua = navigator.userAgent
  const vendor = navigator.vendor
  const isChromium = /Chrome|CriOS|Edg\//.test(ua)
  const isSafari = /Safari\//.test(ua) && !/Chrome|CriOS|Chromium|Edg\//.test(ua)
  return isChromium && (vendor.includes('Google') || ua.includes('Edg/')) && !isSafari
}

const chromeSupported = isChromeBrowser()

function showCenterCopy(text: string, clickable = false) {
  chromeCta.hidden = false
  openChromeCopy.textContent = text
  openChromeCopy.style.cursor = clickable ? 'pointer' : 'default'
}

function hideCenterCopy() {
  chromeCta.hidden = true
}

function getUiFontSize() {
  return UI_FONT_SIZE
}

const btnSpeed = document.getElementById('btn-speed') as HTMLSpanElement
let is2x = false

const videoWrap = document.getElementById('video-wrap') as HTMLDivElement
btnSpeed.addEventListener('click', () => {
  is2x = !is2x
  videoWrap.style.width = is2x ? '576px' : '288px'
  btnSpeed.textContent = is2x ? '1x' : '2x'
})

btnToggle.addEventListener('click', () => {
  videoPanel.classList.toggle('collapsed')
  btnToggle.textContent = videoPanel.classList.contains('collapsed') ? 'show video again' : 'hide'
})

// --- Capture audio from this tab via screen share ---
async function connectAudio() {
  try {
    // Prefer sharing this specific tab for seamless UX
    const stream = await navigator.mediaDevices.getDisplayMedia({
      video: true,
      audio: true,
      // @ts-ignore — preferCurrentTab is supported in Chrome/Edge
      preferCurrentTab: true,
    })

    // Kill the video capture track — we only need audio
    stream.getVideoTracks().forEach(t => t.stop())

    const audioTracks = stream.getAudioTracks()
    if (audioTracks.length === 0) {
      showCenterCopy('no audio — retry', true)
      return
    }

    const audioCtx = new AudioContext()
    const source = audioCtx.createMediaStreamSource(new MediaStream(audioTracks))
    analyser = audioCtx.createAnalyser()
    analyser.fftSize = 2048
    analyser.smoothingTimeConstant = 0.75
    source.connect(analyser)

    freqData = new Uint8Array(analyser.frequencyBinCount)
    audioConnected = true
    hideCenterCopy()
    videoPanel.hidden = false
    canvas.classList.add('audio-connected')

    // Load YouTube iframe only after audio is connected
    const ytSrc = ytFrame.getAttribute('data-src')
    if (ytSrc && !ytFrame.src) ytFrame.src = ytSrc
  } catch {
    showCenterCopy('connect audio', true)
  }
}

// Map frequency bins → per-line amplitude values (0..1)
// Low frequencies (bass) at the center, highs at the edges — like a mirrored spectrum
function getLineBands(totalLines: number): Float32Array {
  if (smoothBands.length !== totalLines) {
    smoothBands = new Float32Array(totalLines)
  }

  if (!analyser || !freqData) {
    // Fallback: gentle idle animation
    for (let i = 0; i < totalLines; i++) {
      smoothBands[i] += (0 - smoothBands[i]) * 0.05
    }
    return smoothBands
  }

  analyser.getByteFrequencyData(freqData)

  // Check audio activity and compute energy level
  let sum = 0
  for (let j = 0; j < freqData.length; j++) sum += freqData[j]
  audioActive = sum > 500
  const rawEnergy = sum / (freqData.length * 255) // 0..1
  audioEnergy += (rawEnergy - audioEnergy) * 0.15  // smooth it

  const binCount = freqData.length
  const halfLines = totalLines / 2

  for (let i = 0; i < totalLines; i++) {
    // Mirror: line 0 and line N-1 are the highest frequencies
    // Center lines are the lowest frequencies (bass)
    const distFromCenter = Math.abs(i - halfLines) / halfLines // 0 at center, 1 at edges

    // Map to frequency bins — bass at center, treble at edges
    // Use a power curve so bass gets more lines (more detail in lows)
    const binPos = distFromCenter * distFromCenter * (binCount - 1)
    const binIdx = Math.floor(binPos)
    const binFrac = binPos - binIdx
    const nextIdx = Math.min(binIdx + 1, binCount - 1)

    // Interpolate between bins
    const raw = (freqData[binIdx] * (1 - binFrac) + freqData[nextIdx] * binFrac) / 255

    // Smooth toward target
    smoothBands[i] += (raw - smoothBands[i]) * SMOOTHING
  }

  return smoothBands
}

function resize() {
  const dpr = devicePixelRatio || 1
  W = innerWidth
  H = innerHeight
  canvas.width = W * dpr
  canvas.height = H * dpr
  canvas.style.width = W + 'px'
  canvas.style.height = H + 'px'
  ctx.setTransform(dpr, 0, 0, dpr, 0, 0)
}

function render(time: number) {
  ctx.clearRect(0, 0, W, H)
  ctx.fillStyle = '#0f0f0f'
  ctx.fillRect(0, 0, W, H)

  // --- Header + social handle (pushed by void) ---
  const uiFontSize = getUiFontSize()
  ctx.font = `${uiFontSize}px "Inter", sans-serif`
  ctx.fillStyle = '#ffffff'
  ctx.textBaseline = 'alphabetic'

  // Logo — each word pushed individually by void
  const logoWords = ['Pretext', ' ', 'again..']
  const logoBaseY = 22 + uiFontSize
  let wordX = 22
  for (const word of logoWords) {
    const wordW = ctx.measureText(word).width
    const wordCx = wordX + wordW / 2
    let wordY = logoBaseY
    if (mouseX > 0 && mouseY > 0) {
      const dx = wordCx - mouseX
      if (Math.abs(dx) < MOUSE_R) {
        const voidTop = mouseY - Math.sqrt(MOUSE_R * MOUSE_R - dx * dx)
        if (voidTop < logoBaseY + 4) {
          wordY = Math.min(logoBaseY, voidTop - 4)
        }
      }
    }
    ctx.fillText(word, wordX, wordY)
    wordX += wordW
  }

  // Social handle
  ctx.textAlign = 'right'
  ctx.fillText('@jaymehoffman', W - 22, H - 22)
  ctx.textAlign = 'left'

  if (!chromeSupported) {
    requestAnimationFrame(render)
    return
  }

  // --- Vertical waveform: columns go left→right, text reads top→bottom ---
  const padY = 22
  const startX = 22
  const endX = W - 22
  const cy = H / 2
  const maxHalf = (H - padY * 2) / 2
  const minHalf = maxHalf * 0.08

  const totalCols = Math.floor((endX - startX) / LH)
  const bands = getLineBands(totalCols)

  // --- Accumulate time scaled by audio energy ---
  const dt = lastFrameTime > 0 ? time - lastFrameTime : 0
  lastFrameTime = time
  if (audioActive) activeTime += dt * (0.3 + audioEnergy * 2.5)

  // --- CD spin + text scroll: only when waveform is going ---
  const angle = activeTime * 0.003456
  const scrollPos = activeTime * SCROLL_RATE / 1000
  const skipIdx = Math.floor(scrollPos) % textCursors.length

  // --- Video panel void rect (with 22px margin) ---
  const panelRect = videoPanel.classList.contains('collapsed') ? null : videoPanel.getBoundingClientRect()
  const panelMargin = 20
  const centerCtaMargin = panelMargin * 2
  const pL = panelRect ? panelRect.left - panelMargin : 0
  const pR = panelRect ? panelRect.right + panelMargin : 0
  const pT = panelRect ? panelRect.top - panelMargin : 0
  const pB = panelRect ? panelRect.bottom + panelMargin : 0
  const centerCtaRect = !chromeCta.hidden && !audioConnected ? openChromeCopy.getBoundingClientRect() : null
  const cL = centerCtaRect ? centerCtaRect.left - centerCtaMargin : 0
  const cR = centerCtaRect ? centerCtaRect.right + centerCtaMargin : 0
  const cT = centerCtaRect ? centerCtaRect.top - centerCtaMargin : 0
  const cB = centerCtaRect ? centerCtaRect.bottom + centerCtaMargin : 0

  let cursor: LayoutCursor = { ...textCursors[skipIdx] }
  let done = false

  for (let i = 0; i < totalCols; i++) {
    if (done) break

    const x = startX + i * LH
    const colMid = x + LH / 2

    // --- Height driven by audio amplitude ---
    const amp = bands[i]
    const halfH = minHalf + (maxHalf - minHalf) * amp

    let shapeTop = Math.max(padY, cy - halfH)
    let shapeBot = Math.min(H - padY, cy + halfH)

    if (shapeBot - shapeTop < MIN_SEGMENT) continue

    // --- Circle void ---
    const mdx = colMid - mouseX
    const inVoid = Math.abs(mdx) < MOUSE_R

    if (inVoid) {
      const halfChord = Math.sqrt(MOUSE_R * MOUSE_R - mdx * mdx)
      const voidTop = mouseY - halfChord
      const voidBot = mouseY + halfChord

      if (voidTop < shapeBot && voidBot > shapeTop) {
        const topH = Math.max(0, Math.min(voidTop, shapeBot) - shapeTop)
        const botH = Math.max(0, shapeBot - Math.max(voidBot, shapeTop))

        // Top section
        if (topH >= MIN_SEGMENT) {
          let line = layoutNextLine(prepared, cursor, topH)
          if (!line) { cursor = { segmentIndex: 0, graphemeIndex: 0 }; line = layoutNextLine(prepared, cursor, topH) }
          if (line) {
            ctx.save()
            ctx.translate(x, shapeTop + topH)
            ctx.rotate(-Math.PI / 2)
            ctx.font = FONT
            ctx.textBaseline = 'top'
            ctx.fillStyle = '#ffffff'
            ctx.fillText(line.text, 0, 0)
            ctx.restore()
            cursor = line.end
          }
        }

        // Bottom section
        if (botH >= MIN_SEGMENT) {
          let line = layoutNextLine(prepared, cursor, botH)
          if (!line) { cursor = { segmentIndex: 0, graphemeIndex: 0 }; line = layoutNextLine(prepared, cursor, botH) }
          if (line) {
            ctx.save()
            ctx.translate(x, shapeBot)
            ctx.rotate(-Math.PI / 2)
            ctx.font = FONT
            ctx.textBaseline = 'top'
            ctx.fillStyle = '#ffffff'
            ctx.fillText(line.text, 0, 0)
            ctx.restore()
            cursor = line.end
          }
        }

        continue
      }
    }

    // --- Video panel void ---
    if (panelRect && colMid >= pL && colMid <= pR && pT < shapeBot && pB > shapeTop) {
      const topH = Math.max(0, Math.min(pT, shapeBot) - shapeTop)
      const botH = Math.max(0, shapeBot - Math.max(pB, shapeTop))

      if (topH >= MIN_SEGMENT) {
        let line = layoutNextLine(prepared, cursor, topH)
        if (!line) { cursor = { segmentIndex: 0, graphemeIndex: 0 }; line = layoutNextLine(prepared, cursor, topH) }
        if (line) {
          ctx.save()
          ctx.translate(x, shapeTop + topH)
          ctx.rotate(-Math.PI / 2)
          ctx.font = FONT
          ctx.textBaseline = 'top'
          ctx.fillStyle = '#ffffff'
          ctx.fillText(line.text, 0, 0)
          ctx.restore()
          cursor = line.end
        }
      }

      if (botH >= MIN_SEGMENT) {
        let line = layoutNextLine(prepared, cursor, botH)
        if (!line) { cursor = { segmentIndex: 0, graphemeIndex: 0 }; line = layoutNextLine(prepared, cursor, botH) }
        if (line) {
          ctx.save()
          ctx.translate(x, shapeBot)
          ctx.rotate(-Math.PI / 2)
          ctx.font = FONT
          ctx.textBaseline = 'top'
          ctx.fillStyle = '#ffffff'
          ctx.fillText(line.text, 0, 0)
          ctx.restore()
          cursor = line.end
        }
      }

      continue
    }

    if (centerCtaRect && colMid >= cL && colMid <= cR && cT < shapeBot && cB > shapeTop) {
      const topH = Math.max(0, Math.min(cT, shapeBot) - shapeTop)
      const botH = Math.max(0, shapeBot - Math.max(cB, shapeTop))

      if (topH >= MIN_SEGMENT) {
        let line = layoutNextLine(prepared, cursor, topH)
        if (!line) { cursor = { segmentIndex: 0, graphemeIndex: 0 }; line = layoutNextLine(prepared, cursor, topH) }
        if (line) {
          ctx.save()
          ctx.translate(x, shapeTop + topH)
          ctx.rotate(-Math.PI / 2)
          ctx.font = FONT
          ctx.textBaseline = 'top'
          ctx.fillStyle = '#ffffff'
          ctx.fillText(line.text, 0, 0)
          ctx.restore()
          cursor = line.end
        }
      }

      if (botH >= MIN_SEGMENT) {
        let line = layoutNextLine(prepared, cursor, botH)
        if (!line) { cursor = { segmentIndex: 0, graphemeIndex: 0 }; line = layoutNextLine(prepared, cursor, botH) }
        if (line) {
          ctx.save()
          ctx.translate(x, shapeBot)
          ctx.rotate(-Math.PI / 2)
          ctx.font = FONT
          ctx.textBaseline = 'top'
          ctx.fillStyle = '#ffffff'
          ctx.fillText(line.text, 0, 0)
          ctx.restore()
          cursor = line.end
        }
      }

      continue
    }

    // --- Normal column ---
    const colH = shapeBot - shapeTop
    let line = layoutNextLine(prepared, cursor, colH)
    if (!line) { cursor = { segmentIndex: 0, graphemeIndex: 0 }; line = layoutNextLine(prepared, cursor, colH) }
    if (!line) continue

    ctx.save()
    ctx.translate(x, shapeBot)
    ctx.rotate(-Math.PI / 2)
    ctx.font = FONT
    ctx.textBaseline = 'top'
    ctx.fillStyle = '#ffffff'
    ctx.fillText(line.text, 0, 0)
    ctx.restore()

    cursor = line.end
  }

  // --- Draw void outline + play/pause cursor ---
  const panelBtnRect = videoPanel.hidden ? null : videoPanel.getBoundingClientRect()
  const overPanel = panelBtnRect && mouseX >= panelBtnRect.left && mouseX <= panelBtnRect.right && mouseY >= panelBtnRect.top && mouseY <= panelBtnRect.bottom
  const linkRect = twitterLink.getBoundingClientRect()
  const overLink = mouseX >= linkRect.left && mouseX <= linkRect.right && mouseY >= linkRect.top && mouseY <= linkRect.bottom
  const overUI = overPanel || overLink
  canvas.style.cursor = audioConnected && !overUI ? 'none' : 'default'
  if (audioConnected && !overUI && mouseX > 0 && mouseY > 0) {
    ctx.save()
    ctx.strokeStyle = '#24BD20'
    ctx.lineWidth = 1
    ctx.beginPath()
    ctx.arc(mouseX, mouseY, MOUSE_R * 0.65, 0, Math.PI * 2)
    ctx.stroke()
    ctx.restore()
  }
  if (audioConnected && !overUI && mouseX > 0 && mouseY > 0) {
    ctx.save()
    ctx.fillStyle = '#ffffff'
    ctx.font = '16px sans-serif'
    ctx.textBaseline = 'middle'
    ctx.textAlign = 'center'
    ctx.fillText(ytPlaying ? '\u23F8' : '\u25B6', mouseX, mouseY)
    ctx.restore()
  }

  requestAnimationFrame(render)
}

// --- YouTube play/pause ---
let ytPlaying = true

function togglePlayPause() {
  if (!chromeSupported || !audioConnected) return
  if (!ytFrame.contentWindow) return
  const cmd = ytPlaying ? 'pauseVideo' : 'playVideo'
  ytFrame.contentWindow.postMessage(JSON.stringify({ event: 'command', func: cmd }), '*')
  ytPlaying = !ytPlaying
}

canvas.addEventListener('click', () => {
  if (!audioConnected) { if (chromeSupported) void connectAudio(); return }
  togglePlayPause()
})
document.addEventListener('keydown', (e) => {
  if (e.code === 'Space') { e.preventDefault(); togglePlayPause() }
  if (e.code === 'Escape') { btnToggle.click() }
  if (e.key === '1') {
    if (videoPanel.classList.contains('collapsed')) { videoPanel.classList.remove('collapsed'); btnToggle.textContent = 'hide' }
    if (is2x) btnSpeed.click()
  }
  if (e.key === '2') {
    if (videoPanel.classList.contains('collapsed')) { videoPanel.classList.remove('collapsed'); btnToggle.textContent = 'hide' }
    if (!is2x) btnSpeed.click()
  }
})

// --- Events ---
openChromeCopy.addEventListener('click', () => {
  if (!chromeSupported || audioConnected) return
  void connectAudio()
})
document.addEventListener('mousemove', (e) => { mouseX = e.clientX; mouseY = e.clientY })
document.addEventListener('mouseleave', () => { mouseX = -9999; mouseY = -9999 })
window.addEventListener('resize', resize)

// Pre-compute a cursor for every line boundary in the full text.
// This lets us jump to any scroll position in O(1).
function precomputeCursors() {
  const avgH = Math.max(100, (H - 44) * 0.4)
  let c: LayoutCursor = { segmentIndex: 0, graphemeIndex: 0 }
  textCursors = [{ segmentIndex: 0, graphemeIndex: 0 }]
  while (true) {
    const line = layoutNextLine(prepared, c, avgH)
    if (!line) break
    c = line.end
    textCursors.push({ segmentIndex: c.segmentIndex, graphemeIndex: c.graphemeIndex })
  }
}

// --- Init ---
function init() {
  if (!chromeSupported) {
    videoPanel.style.display = 'none'
    showCenterCopy('open again in chrome')
    resize()
    requestAnimationFrame(render)
    return
  }

  showCenterCopy('connect audio', true)
  videoPanel.hidden = true
  prepared = prepareWithSegments(TEXT, FONT)
  resize()
  precomputeCursors()
  requestAnimationFrame(render)
}

document.fonts.ready.then(init)
